// Get tool by slug
export function getToolBySlugEn(slug: string): ToolMeta | undefined {
  return toolsEn.find((tool) => tool.slug === slug);
}

// Get tools by category
export function getToolsByCategoryEn(category: string): ToolMeta[] {
  return toolsEn.filter((tool) => tool.category === category);
}

// Get all tool slugs
export function getAllToolSlugsEn(): string[] {
  return toolsEn.map((tool) => tool.slug);
}

// Get featured tools
export function getFeaturedToolsEn(): ToolMeta[] {
  return toolsEn.filter((tool) => tool.featured);
}

// Get related tools
export function getRelatedToolsEn(slugs: string[]): ToolMeta[] {
  return slugs
    .map((slug) => getToolBySlugEn(slug))
    .filter((tool): tool is ToolMeta => tool !== undefined);
}
